mapper.select:
SELECT ma.mbr_acct_idx AS idx, ma.mbr_acct_uuid AS uuid, ma.lgn_id, ma.pwd, ma.email, ma.role, mp.nick_nm, mp.intro, ma.created_by, ma.updated_by, ma.created_at, ma.updated_at, ma.del_at FROM tb_mbr_acct ma LEFT JOIN tb_mbr_prfl mp ON mp.mbr_acct_idx = ma.mbr_acct_idx WHERE 1 = 1
AND ma.del_at IS NULL
AND ( ma.lgn_id LIKE CONCAT('%', #{req.kwd}, '%') OR ma.email LIKE CONCAT('%', #{req.kwd}, '%') )
AND ma.role = #{req.role}
ORDER BY ${req.orderByClause} LIMIT #{req.size} OFFSET #{req.offset}
